const express = require('express');
const router = express.Router();

router.get('/callback', (req, res) => {
  const returnUrl = req.query.return_url;
  if (!returnUrl || !isValidRedirectTarget(returnUrl)) {
    res.status(403).send('Invalid redirect target');
    return;
  }
  res.redirect(returnUrl);
});

function isValidRedirectTarget(target) {
  // Check if the target is a valid URL and not an external domain
  try {
    const url = new URL(target);
    if (url.hostname !== 'localhost' && !url.hostname.endsWith('.example.com')) {
      return false;
    }
  } catch (e) {
    return false;
  }
  // Check if the target is a valid internal route name/path
  const allowedRoutes = ['/', '/home', '/profile'];
  if (!allowedRoutes.includes(target)) {
    return false;
  }
  return true;
}